// process-goal-car-sprites.mjs — Bug D: split sprite-sources/raw/goal-cars.png
// (3×2 montage of stylized single-color counter icons, white bg, generated by
// scripts/generate-goal-car-montage.mjs) into public/sprites/designed/
// goal-car-{color}.png. Same pipeline conventions as the powerballs: flood-fill
// bg removal from the edges, crop to content, 256×256 transparent.
// Run: node scripts/process-goal-car-sprites.mjs

import sharp from 'sharp';
import path from 'path';
import { fileURLToPath } from 'url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const SRC = path.join(__dirname, '..', 'sprite-sources', 'raw', 'goal-cars.png');
const OUT = path.join(__dirname, '..', 'public', 'sprites', 'designed');
const SIZE = 256;

const ORDER = ['red', 'blue', 'green', 'yellow', 'purple', 'orange'];   // montage grid order
const COLS = 3, ROWS = 2;

// Flood-fill near-white background from the edges → alpha 0 (same as powerballs).
function floodFillBackground(data, width, height, threshold = 235, satThreshold = 0.12) {
  const visited = new Uint8Array(width * height);
  const isBg = (i) => {
    const r = data[i], g = data[i + 1], b = data[i + 2];
    const max = Math.max(r, g, b), min = Math.min(r, g, b);
    const sat = max === 0 ? 0 : (max - min) / max;
    return r > threshold && g > threshold && b > threshold && sat < satThreshold;
  };
  const stack = [];
  const seed = (px, py) => {
    const i = py * width + px;
    if (!visited[i] && isBg(i * 4)) { visited[i] = 1; stack.push(i); }
  };
  for (let x = 0; x < width; x++) { seed(x, 0); seed(x, height - 1); }
  for (let y = 0; y < height; y++) { seed(0, y); seed(width - 1, y); }
  while (stack.length) {
    const i = stack.pop();
    data[i * 4 + 3] = 0;
    const x = i % width, y = (i / width) | 0;
    for (const [nx, ny] of [[x-1,y],[x+1,y],[x,y-1],[x,y+1]]) {
      if (nx < 0 || nx >= width || ny < 0 || ny >= height) continue;
      const ni = ny * width + nx;
      if (!visited[ni] && isBg(ni * 4)) { visited[ni] = 1; stack.push(ni); }
    }
  }
}

const meta = await sharp(SRC).metadata();
const CELL_W = Math.floor(meta.width / COLS), CELL_H = Math.floor(meta.height / ROWS);

for (const [i, color] of ORDER.entries()) {
  const col = i % COLS, row = (i / COLS) | 0;
  const cell = await sharp(SRC)
    .extract({ left: col * CELL_W, top: row * CELL_H, width: CELL_W, height: CELL_H })
    .ensureAlpha().raw().toBuffer({ resolveWithObject: true });
  const px = new Uint8Array(cell.data.buffer);
  floodFillBackground(px, cell.info.width, cell.info.height);

  // Crop to content (alpha bbox) then contain into the square canvas.
  let minX = cell.info.width, maxX = -1, minY = cell.info.height, maxY = -1;
  for (let y = 0; y < cell.info.height; y++) for (let x = 0; x < cell.info.width; x++) {
    if (px[(y * cell.info.width + x) * 4 + 3] > 10) {
      if (x < minX) minX = x; if (x > maxX) maxX = x;
      if (y < minY) minY = y; if (y > maxY) maxY = y;
    }
  }
  const out = path.join(OUT, `goal-car-${color}.png`);
  await sharp(Buffer.from(px), { raw: { width: cell.info.width, height: cell.info.height, channels: 4 } })
    .extract({ left: minX, top: minY, width: maxX - minX + 1, height: maxY - minY + 1 })
    .resize(SIZE, SIZE, { fit: 'contain', background: { r: 0, g: 0, b: 0, alpha: 0 } })
    .png()
    .toFile(out);
  const m = await sharp(out).metadata();
  console.log(`  ✓ goal-car-${color}.png ${m.width}×${m.height} alpha:${m.hasAlpha} (content ${maxX - minX + 1}×${maxY - minY + 1})`);
}
